var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"북극점 공방전 최종전     \\n<color=#ffd34c>네임리스 원</color>과의 최초 교전 이후 27시간 경과","JPN":"北極点攻防最終戦     \\n<color=#ffd34c>ネームレスワン</color>との最初の交戦から27時間経過","ENG":"[[","TWN":"北極點攻防戰決戰 距離與\\n<color=#ffd34c>無名1</color>第一次交戰已經過27小時","THA":"ด่านสุดท้ายของศึกขั้วโลกเหนือ     \\n27 ชั่วโมงหลังการเริ่มปะทะกับ<color=#ffd34c>ผู้ไร้นาม</color>","VTN":"Giai đoạn cuối cùng của Trận Chiến Bắc Cực \\n27 giờ sau lần giao tranh đầu tiên với <color=#ffd34c>Kẻ Vô Danh</color> ","SCN":"北极点攻防战决战 距离与\\n<color=#ffd34c>无名氏</color>的第一次交战已经过去27个小时","DEU":"[[","FRA":"Ultime assaut de la Bataille du pôle Nord     \\n27 heures après l'engagement du combat avec le <color=#ffd34c>Sans Nom</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그만 두십쇼, 사령관님!","JPN":"おやめください、司令官！","ENG":"You can't do that, Commander!","TWN":"放棄吧，司令官大人！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이건 자살행위나 다름없습니다! 다시는 빠져 나오지 못할 겁니다!","JPN":"これは自殺行為に他なりません！　二度と抜け出せなくなります！","ENG":"This is suicide! You'll never be able to come back!","TWN":"您這樣跟自殺行為沒什麼兩樣！一切會再也無法挽回呀！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"하지만 네임리스 원을 쓰러트리려면 이 방법뿐이야, 도미닉.","JPN":"しかしネームレスワンを倒すにはこれしかない、ドミニーク。","ENG":"But this is the only way to defeat the Nameless One, Dominic.","TWN":"但想要擊敗無名1，就只有這個方法了，多明尼克。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아니요! 분명 다른 방법이 있을 겁니다.","JPN":"いいえ！　きっと他の方法があるはずです。","ENG":"No! There must be another way!","TWN":"不！一定有其他辦法的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"그럴지도 모르지......","JPN":"そうかもしれない……","ENG":"There could be...","TWN":"或許吧……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"하지만 그런 방법을 찾기엔 시간이 부족해.","JPN":"しかし、他の手を探すには時間がない。","ENG":"But we don't have enough time to find one.","TWN":"可是我們沒有時間找別的辦法了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"지금도 놈을 막기 위한 병사들의 희생은 계속되고 있어.","JPN":"今この瞬間も、奴を止めるために兵士の犠牲は続いている。","ENG":"Even now, soldiers are sacrificing their lives to stop the Nameless One.","TWN":"現在為了擋住那傢伙，士兵們還在不斷犧牲。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"이젠 생각이 아닌 결단을 내려야만 해.","JPN":"考える時ではなく、決断を下す時が来た。","ENG":"Now's the time to decide, not to think.","TWN":"現在要做的不是思考，而是決斷。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"알다시피 우리가 가진 어떤 화력으로도 놈을 완전히 죽일 수는 없어.","JPN":"知ってのとおり、我々が持っている力では奴を完全に仕留めることはできない。","ENG":"As you know, none of our weapons can kill this beast completely.","TWN":"如你所知，我們現在用任何火力都沒辦法完全殺死那傢伙。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"그렇다면 남은 방법은 놈을 현실세계로부터 격리시키는 수 밖에.","JPN":"ならば残された方法は、奴を現実世界から隔離することのみ。","ENG":"Then the only remaining option is to isolate it far from the Normalside.","TWN":"那麼，剩下的辦法只能是將它與現實世界隔離。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"내 능력을 한계까지 끌어낸다면 차원 함선도 도달할 수 없을 만큼 깊은 심도까지 통하는 길을 잠시나마 열 수 있겠지.","JPN":"私の能力を限界まで引き出せば、少しの間なら次元艦船でも到達できないほどの深度に通じる道を開けられるだろう。","ENG":"If I push my ability to the limit, I'll be able to open a passage to the hyperdepths that even dimensional ships can't reach.","TWN":"如果把我的能力爆發到極限，就可以暫時開啟一條通往超深度的路，連次元艦船都無法到達。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"그곳으로 놈을 밀어 넣을 수만 있다면...... 이 싸움도 끝날 거야.","JPN":"そこに奴を押し込めることができれば……この戦いも終わる。","ENG":"If we can push the Nameless One into that passage... this fight will be over.","TWN":"只要能將那傢伙推進去……這場戰鬥也會結束。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만......","JPN":"ですが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"더 이상의 반대는 듣지 않겠어!","JPN":"それ以上の反対は無用だ！","ENG":"I won't hear any more objections!","TWN":"我不想繼續聽反對意見了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"전 부대, 내가 차원 통로를 열고 네임리스 원과 교전을 시작하면 모든 화력을 집중하라!","JPN":"全部隊、私が次元通路を開いてネームレスワンと交戦を開始したら、すべての火力を集中せよ！","ENG":"All units, listen up! Once I open a dimensional passage and engage the Nameless One, concentrate all firepower!","TWN":"全體聽令，在我打開次元通道與無名1交戰後，要集中所有火力攻擊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"기회는 한 번뿐이다! 절대 실수하지 말도록!","JPN":"チャンスは一度のみ！　絶対に失敗は許されない！","ENG":"We have only one chance! Don't screw up!","TWN":"只有一次機會！絕對不能失誤！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};